from dataclasses import dataclass, field
from typing import List, Optional

@dataclass
class Beat:
    t: int                          # minutes from start
    inject: dict                    # chaos action
    expect_detection_within_min: Optional[int] = None
    complication: Optional[str] = None

@dataclass
class GamedayScenario:
    scenario_id: str
    title: str
    severity_target: str
    duration_minutes: int
    incident_type_tag: str
    beats: List[Beat] = field(default_factory=list)

    def validate(self) -> list[str]:
        errors = []
        if not self.beats:
            errors.append("Scenario must have at least one beat")
        if self.beats and self.beats[0].t != 0:
            errors.append("First beat must be at t=0 (initial injection)")
        if self.severity_target not in ("P0", "P1", "P2", "P3", "P4"):
            errors.append(f"Invalid severity_target: {self.severity_target}")
        return errors

from datetime import date

REFRESH_INTERVAL_DAYS = 90
MIN_ESCALATION_SCORE = 2.0

def ic_refresh_status(ic_id: str, roster: dict) -> dict:
    """
    Returns {status: current | refresh_required | coaching_plan,
             action: <str>}
    """
    entry = roster[ic_id]
    days_since = (date.today() - entry["last_incident_date"]).days

    if entry.get("escalation_score", 5.0) < MIN_ESCALATION_SCORE:
        return {
            "status": "coaching_plan",
            "action": "Complete coached gameday before returning to rotation",
        }
    if days_since > REFRESH_INTERVAL_DAYS:
        return {
            "status": "refresh_required",
            "action": f"Complete one shadow drill ({days_since}d since last incident)",
        }
    return {"status": "current", "action": "No action required"}
